                (image_data ? (
                  <ChatBubble_Actions_Image image_data={image_data} />
                ) : (
                  <ChatBubble_Actions
                    loading={loading}
                    message_id={message_id}
                    pinned={pinned}
                    text={text}
                    messageRole="assistant"
                    onRetry={onRetry}
                    isRetrying={isRetrying}
                  />
                ))}
            </div>
          </div>
        )}

        {children}
      </div>
    )
  );
}

