    <m.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4, ease: EASE_OUT_QUART }}
      className="mx-2 rounded-2xl bg-zinc-800 p-4"
    >
      <div className="mb-3 flex items-center justify-between">
        <Tabs
          aria-label="Clarify questions"
          selectedKey={activeId}
          onSelectionChange={(key) =>
            dispatch({ type: "clarifyTab", questionId: String(key) })
          }
          size="sm"
          variant="solid"
          radius="full"
          classNames={{ tabList: "bg-zinc-900" }}
        >
          {questions.map((q, idx) => {
            const answered = isQuestionAnswered(
              state.clarifyAnswers[q.id],
              state.clarifyCustomDrafts[q.id],
            );
            return (
              <Tab
                key={q.id}
                title={
                  <span className="flex items-center gap-1.5">
                    <span>Q{idx + 1}</span>
                    {answered && (
                      <CheckmarkCircle02Icon className="size-3 text-emerald-400" />
                    )}
                  </span>
                }
              />
            );
          })}
        </Tabs>
        <span className="text-xs text-zinc-500">
          {answeredCount} / {questions.length}
        </span>
      </div>

      <AnimatePresence mode="wait" initial={false}>
        <m.div
          key={activeQuestion.id}
          initial={{ opacity: 0, y: 8 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -8 }}
          transition={{ duration: 0.25, ease: EASE_OUT_QUART }}
          className="rounded-2xl bg-zinc-900 p-3"
        >
          <p className="mb-3 text-sm text-zinc-100">
            {activeQuestion.question}
          </p>

          <RadioGroup
            value={selectedValue ?? ""}
            onValueChange={handleRadioChange}
            classNames={{ wrapper: "gap-1.5" }}
          >
            {activeQuestion.options.map((option, idx) => (
              <Radio
                key={option}
                value={`${OPTION_VALUE_PREFIX}${idx}`}
                classNames={{
                  base: CLARIFY_RADIO_BASE_CLASS,
                  label: CLARIFY_RADIO_LABEL_CLASS,
                }}
              >
                {option}
              </Radio>
            ))}
            <Radio
              value={OTHER_VALUE}
              classNames={{
                base: CLARIFY_RADIO_BASE_CLASS,
                label: CLARIFY_RADIO_LABEL_CLASS,
              }}
            >
              {CLARIFY_OTHER_LABEL}
            </Radio>
            <AnimatePresence initial={false}>
              {isOtherSelected && (
                <m.div
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: "auto" }}
                  exit={{ opacity: 0, height: 0 }}
                  transition={{ duration: 0.25, ease: EASE_OUT_QUART }}
                  className="overflow-hidden"
                >
                  <Input
                    autoFocus
                    size="sm"
                    value={activeDraft}
                    onValueChange={handleCustomChange}
                    onBlur={handleCustomCommit}
                    placeholder="Type your answer..."
                    classNames={{ inputWrapper: "bg-zinc-800" }}
                  />
                </m.div>
              )}
            </AnimatePresence>
            <Radio
              value={SKIP_VALUE}
              classNames={{
                base: CLARIFY_RADIO_BASE_CLASS,
                label: CLARIFY_RADIO_LABEL_MUTED_CLASS,
              }}
            >
              {CLARIFY_SKIP_LABEL}
            </Radio>
          </RadioGroup>
        </m.div>
      </AnimatePresence>

      <div className="mt-3 flex justify-end">
        <Button
          color="primary"
          radius="full"
          size="sm"
          isDisabled={!allAnswered}
          onPress={handleSubmit}
          endContent={<CircleArrowRight02Icon className="size-4" />}
        >
          Submit & continue
        </Button>
      </div>
    </m.div>
  );
}

